
  // ---------- DATA ----------
  let cart = []; // {id,name,price,qty,img}
  let selectedMethod = null;

  const rupiah = n => 'Rp ' + n.toLocaleString('id-ID');

  // ---------- SIDEBAR ----------
  function toggleSidebar(open){
    document.getElementById('sidebar').classList.toggle('show', open);
  }
  function scrollToId(id){
    document.getElementById(id).scrollIntoView({behavior:'smooth'});
    toggleSidebar(false);
  }

  // ---------- HERO SLIDER ----------
  const slides = document.querySelectorAll('.hero-slide');
  let slideIndex = 0;
  const track = document.getElementById('heroTrack');
  const dotsWrap = document.getElementById('heroDots');
  slides.forEach((s,i)=>{
    const dot = document.createElement('span');
    if(i===0) dot.classList.add('active');
    dotsWrap.appendChild(dot);
  });
  function renderSlide(){
    track.style.transform = `translateX(-${slideIndex*100}%)`;
    document.querySelectorAll('.hero-dots span').forEach((d,i)=>d.classList.toggle('active', i===slideIndex));
  }
  function changeSlide(dir){
    slideIndex = (slideIndex + dir + slides.length) % slides.length;
    renderSlide();
  }
  function scrollToProduct(id){
    const el = document.getElementById('prod-'+id);
    if(el){
      el.scrollIntoView({behavior:'smooth', block:'center'});
      el.classList.add('highlight');
      setTimeout(()=>el.classList.remove('highlight'), 2000);
    }
  }

  // ---------- SEARCH ----------
  function doSearch(){
    const q = document.getElementById('searchInput').value.trim().toLowerCase();
    if(!q) return;
    const cards = document.querySelectorAll('.product-card');
    let found = null;
    cards.forEach(c=>{
      if(c.dataset.name.includes(q)) found = found || c;
    });
    if(found){
      found.scrollIntoView({behavior:'smooth', block:'center'});
      found.classList.add('highlight');
      setTimeout(()=>found.classList.remove('highlight'), 2000);
    } else {
      alert('Produk "'+q+'" tidak ditemukan di katalog 🍪');
    }
  }

  // ---------- CART ----------
  function addToCart(id,name,price,img){
    const existing = cart.find(i=>i.id===id);
    if(existing) existing.qty++;
    else cart.push({id,name,price,qty:1,img});
    renderCart();
    toggleCart(true);
  }
  function changeQty(id, delta){
    const item = cart.find(i=>i.id===id);
    if(!item) return;
    item.qty += delta;
    if(item.qty<=0) cart = cart.filter(i=>i.id!==id);
    renderCart();
  }
  function removeItem(id){
    cart = cart.filter(i=>i.id!==id);
    renderCart();
  }
  function resetCart(){
    if(cart.length===0) return;
    if(confirm('Kosongkan keranjang?')){
      cart = [];
      renderCart();
    }
  }
  function cartTotalValue(){
    return cart.reduce((sum,i)=>sum + i.price*i.qty, 0);
  }
  function renderCart(){
    const body = document.getElementById('cartBody');
    const badge = document.getElementById('cartBadge');
    const totalCount = cart.reduce((s,i)=>s+i.qty,0);
    badge.textContent = totalCount;
    if(cart.length===0){
      body.innerHTML = '<div class="empty-msg">Keranjang masih kosong. Yuk pilih jajanan manismu! 🍰</div>';
    } else {
      body.innerHTML = cart.map(i=>`
        <div class="cart-item">
          <img src="${i.img}" alt="${i.name}">
          <div class="ci-info">
            <h4>${i.name}</h4>
            <span>${rupiah(i.price)}</span>
          </div>
          <div class="qty-ctrl">
            <button onclick="changeQty('${i.id}',-1)">−</button>
            <span>${i.qty}</span>
            <button onclick="changeQty('${i.id}',1)">+</button>
          </div>
          <button class="remove-btn" onclick="removeItem('${i.id}')">🗑️</button>
        </div>
      `).join('');
    }
    document.getElementById('cartTotal').textContent = rupiah(cartTotalValue());
  }
  function toggleCart(open){
    document.getElementById('cartDrawer').classList.toggle('show', open);
    document.getElementById('overlay').classList.toggle('show', open);
  }

  // ---------- ORDER FORM ----------
  function openOrderForm(){
    if(cart.length===0){ alert('Keranjang kosong, yuk pilih produk dulu 🍩'); return; }
    toggleCart(false);
    const list = document.getElementById('orderItemsList');
    list.innerHTML = cart.map(i=>`<div><span>${i.name} x${i.qty}</span><span>${rupiah(i.price*i.qty)}</span></div>`).join('')
      + `<div style="font-weight:800; border-top:1px solid var(--light-brown); margin-top:6px; padding-top:6px;"><span>Total</span><span>${rupiah(cartTotalValue())}</span></div>`;
    selectedMethod = null;
    document.querySelectorAll('.pay-option').forEach(p=>p.classList.remove('selected'));
    document.getElementById('orderModal').classList.add('show');
  }
  function selectPayment(method){
    selectedMethod = method;
    document.querySelectorAll('.pay-option').forEach(p=>{
      p.classList.toggle('selected', p.dataset.method===method);
    });
  }
  function closeModal(id){
    document.getElementById(id).classList.remove('show');
  }

  function goToPayment(){
    const name = document.getElementById('ordName').value.trim();
    const address = document.getElementById('ordAddress').value.trim();
    const phone = document.getElementById('ordPhone').value.trim();
    if(!name || !address || !phone){
      alert('Mohon lengkapi Nama, Alamat, dan No Handphone terlebih dahulu ya 🙏');
      return;
    }
    if(!selectedMethod){
      alert('Silakan pilih metode pembayaran dulu 💳');
      return;
    }
    const total = cartTotalValue();
    const detail = document.getElementById('payDetail');
    const title = document.getElementById('payTitle');

    if(selectedMethod==='cash'){
      title.textContent = '💵 Pembayaran Cash (COD)';
      detail.innerHTML = `<p>Silakan siapkan pembayaran tunai saat pesanan diterima.</p>
        <div class="grand-total">${rupiah(total)}</div>`;
    } else if(selectedMethod==='qris'){
      title.textContent = '📱 Pembayaran QRIS';
      detail.innerHTML = `<p>Scan QR code di bawah untuk membayar</p>
        <img src="data:image/jpeg;base64," width="220" alt="QRIS Bite Me Bakery">
        <div class="grand-total">${rupiah(total)}</div>
        <p style="font-size:.75rem; margin-top:6px; opacity:.7;">NMID: ID1026541406330</p>`;
    } else if(selectedMethod==='bni'){
      title.textContent = '🏦 Transfer Bank BNI';
      detail.innerHTML = `<p>Transfer ke rekening berikut:</p>
        <div class="rek">1980211429 (a.n. Bite Me Bakery)</div>
        <div class="grand-total">${rupiah(total)}</div>`;
    } else if(selectedMethod==='dana'){
      title.textContent = '💙 E-Wallet DANA';
      detail.innerHTML = `<p>Transfer ke nomor DANA berikut:</p>
        <div class="rek">083844266007 (a.n. Bite Me Bakery)</div>
        <div class="grand-total">${rupiah(total)}</div>`;
    }
    closeModal('orderModal');
    document.getElementById('paymentModal').classList.add('show');
  }

  function finishOrder(){
    closeModal('paymentModal');
    alert('Terima kasih! Pesananmu sudah kami catat 🍩💕 Kami akan segera menghubungimu.');
    cart = [];
    renderCart();
  }

  renderCart();
  renderSlide();
